	"github.com/cilium/tetragon/pkg/watcher"
)

func TestGetPodInfo_IncludesPodUID(t *testing.T) {
	controller := true
	pod := &v1.Pod{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-pod",
			Namespace: "kube-system",
			UID:       "pod-uid-123",
			OwnerReferences: []metav1.OwnerReference{
				{
					Name:       "test-workload",
					Kind:       "Deployment",
					Controller: &controller,
				},
			},
		},
		Status: v1.PodStatus{
			ContainerStatuses: []v1.ContainerStatus{{
				Image:       "image-name",
				ImageID:     "image-id",
				ContainerID: "containerd://abcd1234",
			}},
		},
	}

	podAccessor := watcher.NewFakeK8sWatcher([]interface{}{pod})
	podInfo := getPodInfo(podAccessor, "abcd1234", "curl", "cilium.io", 1)

	assert.NotNil(t, podInfo)
	assert.True(t, proto.Equal(&tetragon.Pod{Uid: "pod-uid-123"}, &tetragon.Pod{Uid: podInfo.Uid}), "expected pod UID to be set")
}

